/**
 * Verify PIN Modal Component
 * 
 * Modal dialog for verifying 4-digit security PIN before processing
 * sensitive transactions. Validates PIN format and communicates with
 * security service for verification.
 */

import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { securityService } from '@/features/settings/services';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { LoadingSpinner } from '@/shared/components';

const VerifyPinModal = ({ open, onClose, onVerified }) => {
  const { t } = useTranslation();
  const [pin, setPin] = useState('');
  const [loading, setLoading] = useState(false);
  const { error: showError } = useToast();
  const inputRef = useRef(null);

  // Auto-focus when modal opens
  useEffect(() => {
    if (open) {
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, [open]);

  if (!open) { return null; }

  const handleVerify = async () => {
    if (loading) return; // Prevent double submission

    if (!/^\d{4}$/.test(pin)) {
      showError(t('pleaseEnterValid4DigitPIN', { ns: 'common' }));
      setPin('');
      inputRef.current?.focus();
      return;
    }
    try {
      setLoading(true);
      const resp = await securityService.verifySecurityPIN(pin);

      // Handle raw response vs data wrapped response
      const code = resp?.code || resp?.data?.code;

      if (code && code !== '00') {
        // Explicitly handle 03 (Invalid PIN) or others
        if (code === '03' || code === 3) {
          showError(t('wrongPIN', { ns: 'common' }));
        } else {
          showError(resp?.message || t('pinVerificationFailed', { ns: 'common' }));
        }
        setPin('');
        inputRef.current?.focus();
        return;
      }

      setPin('');
      onVerified?.();
    } catch (e) {
      const msg = (e?.message || '').toLowerCase();
      const code = e?.code || e?.response?.data?.code;

      if (code === '03' || code === 3 || msg.includes('03') || msg.includes('invalid') || msg.includes('wrong')) {
        showError(t('wrongPIN', { ns: 'common' }));
      } else {
        showError(e?.message || t('pinVerificationFailed', { ns: 'common' }));
      }
      setPin('');
      inputRef.current?.focus();
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && pin.length === 4 && !loading) {
      handleVerify();
    }
  };

  return createPortal(
    <>
      <div style={{
        position: 'fixed',
        inset: 0,
        backgroundColor: 'rgba(0,0,0,0.5)',
        backdropFilter: 'blur(4px)',
        zIndex: 10001
      }} />
      <div style={{
        position: 'fixed',
        inset: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 10002,
        pointerEvents: 'none'
      }}>
        <div style={{
          backgroundColor: 'var(--card)',
          borderRadius: 16,
          padding: 32,
          width: '100%',
          maxWidth: 420,
          boxShadow: 'var(--shadow-xl)',
          animation: 'slideIn 0.3s ease-out',
          pointerEvents: 'auto'
        }}>
          {/* Header with Icon */}
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            marginBottom: 24
          }}>
            <div style={{
              width: 64,
              height: 64,
              borderRadius: '50%',
              background: 'linear-gradient(135deg, #004895 0%, #003d7a 100%)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              marginBottom: 16,
              boxShadow: '0 4px 12px rgba(0, 72, 149, 0.3)'
            }}>
              <span className="material-symbols-outlined" style={{
                fontSize: 32,
                color: 'white'
              }}>
                lock
              </span>
            </div>
            <h3 style={{
              margin: 0,
              marginBottom: 8,
              color: 'var(--text-primary)',
              fontSize: '24px',
              fontWeight: 700
            }}>
              {t('enterPIN', { ns: 'common', defaultValue: 'Enter PIN' })}
            </h3>
            <p style={{
              margin: 0,
              color: 'var(--text-muted)',
              fontSize: '14px',
              textAlign: 'center',
              lineHeight: '20px'
            }}>
              {t('enter4DigitPIN', { ns: 'common' })}
            </p>
          </div>

          {/* PIN Input */}
          <div style={{ marginBottom: 24 }}>
            <input
              ref={inputRef}
              type="password"
              inputMode="numeric"
              pattern="\\d{4}"
              maxLength={4}
              placeholder=""
              value={pin}
              onChange={(e) => setPin(e.target.value.replace(/[^0-9]/g, ''))}
              onKeyDown={handleKeyDown}
              autoFocus
              style={{
                width: '100%',
                padding: '16px 20px',
                fontSize: '24px',
                fontWeight: 600,
                letterSpacing: '8px',
                textAlign: 'center',
                borderRadius: 12,
                border: pin ? '2px solid var(--accent)' : '2px solid var(--border-primary)',
                background: 'var(--bg-tertiary)',
                color: 'var(--text-primary)',
                transition: 'all 0.2s ease',
                boxSizing: 'border-box'
              }}
              onFocus={(e) => {
                e.target.style.borderColor = 'var(--accent)';
                e.target.style.background = 'var(--bg-input)';
                e.target.style.boxShadow = '0 0 0 4px rgba(59, 130, 246, 0.1)';
              }}
              onBlur={(e) => {
                e.target.style.borderColor = pin ? 'var(--accent)' : 'var(--border-primary)';
                e.target.style.background = 'var(--bg-tertiary)';
                e.target.style.boxShadow = 'none';
              }}
            />
          </div>

          {/* Buttons */}
          <div style={{ display: 'flex', gap: 12 }}>
            <button
              type="button"
              onClick={() => { setPin(''); onClose?.(); }}
              style={{
                flex: 1,
                padding: '14px 20px',
                borderRadius: 10,
                border: '2px solid var(--border-primary)',
                background: 'var(--bg-input)',
                color: 'var(--text-secondary)',
                cursor: 'pointer',
                fontSize: '15px',
                fontWeight: 600,
                transition: 'all 0.2s ease'
              }}
              onMouseEnter={(e) => {
                e.target.style.borderColor = 'var(--border-secondary)';
                e.target.style.background = 'var(--bg-hover)';
              }}
              onMouseLeave={(e) => {
                e.target.style.borderColor = 'var(--border-primary)';
                e.target.style.background = 'var(--bg-input)';
              }}
            >
              {t('cancel', { ns: 'common' })}
            </button>
            <button
              type="button"
              onClick={handleVerify}
              disabled={loading || pin.length !== 4}
              style={{
                flex: 1,
                padding: '14px 20px',
                borderRadius: 10,
                border: 'none',
                background: (loading || pin.length !== 4) ? 'var(--text-muted)' : 'var(--accent)',
                color: 'var(--text-inverse)',
                cursor: (loading || pin.length !== 4) ? 'not-allowed' : 'pointer',
                fontSize: '15px',
                fontWeight: 600,
                transition: 'all 0.2s ease',
                boxShadow: (loading || pin.length !== 4) ? 'none' : 'var(--shadow-md)'
              }}
              onMouseEnter={(e) => {
                if (!loading && pin.length === 4) {
                  e.target.style.background = 'var(--accent-hover)';
                  e.target.style.boxShadow = 'var(--shadow-lg)';
                  e.target.style.transform = 'translateY(-1px)';
                }
              }}
              onMouseLeave={(e) => {
                if (!loading && pin.length === 4) {
                  e.target.style.background = 'var(--accent)';
                  e.target.style.boxShadow = 'var(--shadow-md)';
                  e.target.style.transform = 'translateY(0)';
                }
              }}
            >
              {loading ? t('verifying', { ns: 'common', defaultValue: 'Verifying...' }) : t('verify', { ns: 'common', defaultValue: 'Verify' })}
            </button>
          </div>

          {/* Loading overlay popup */}
          {loading && (
            <div style={{
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              backgroundColor: 'rgba(255, 255, 255, 0.4)',
              backdropFilter: 'blur(1px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              zIndex: 10,
              borderRadius: 16
            }}>
              <LoadingSpinner size="medium" />
            </div>
          )}
        </div>

        <style>{`
        @keyframes slideIn {
          from {
            opacity: 0;
            transform: translateY(-20px) scale(0.95);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }

        @media (max-width: 1024px) {
          div[style*="maxWidth: 420"] {
            max-width: min(90vw, 400px) !important;
          }
          div[style*="padding: 32"] {
            padding: 24px !important;
          }
        }

        @media (max-width: 768px) {
          div[style*="maxWidth: 420"] {
            max-width: min(95vw, 380px) !important;
          }
          div[style*="padding: 32"] {
            padding: 20px !important;
          }
          h3[style*="fontSize: '24px'"] {
            font-size: 20px !important;
          }
          div[style*="marginBottom: 24"] {
            margin-bottom: 18px !important;
          }
        }

        @media (max-width: 480px) {
          div[style*="maxWidth: 420"] {
            max-width: calc(100vw - 16px) !important;
          }
          div[style*="padding: 32"] {
            padding: 16px !important;
          }
          h3[style*="fontSize: '24px'"] {
            font-size: 18px !important;
          }
          p[style*="fontSize: '14px'"] {
            font-size: 12px !important;
          }
          div[style*="marginBottom: 24"] {
            margin-bottom: 16px !important;
          }
          input[style*="padding: '16px 20px'"] {
            padding: 12px 16px !important;
            font-size: 20px !important;
            letter-spacing: 4px !important;
          }
          button[style*="padding: '14px 20px'"] {
            padding: 10px 14px !important;
            font-size: 13px !important;
          }
          div[style*="width: 64"][style*="height: 64"] {
            width: 48px !important;
            height: 48px !important;
          }
          span[style*="fontSize: 32"][style*="color: 'white'"] {
            font-size: 24px !important;
          }
        }
      `}</style>
      </div>
    </>,
    document.body
  );
};

export default VerifyPinModal;
