/**
 * Set PIN Prompt Modal Component
 * 
 * Modal dialog prompting users to set a security PIN when attempting
 * transactions without one. Navigates to appropriate settings page
 * based on user type (individual or business).
 */

import React from 'react';
import { createPortal } from 'react-dom';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const SetPinPromptModal = ({ open, onClose }) => {
  const navigate = useNavigate();
  const { t } = useTranslation();

  if (!open) {return null;}

  const handleGoToSettings = () => {
    // Get user type from localStorage (same logic as Settings component)
    const userData = JSON.parse(localStorage.getItem('userData') || '{}');
    const storedUserType = localStorage.getItem('userType') || localStorage.getItem('user_type');
    const userType = (userData?.userType || userData?.user_type || userData?.usertype || storedUserType || 'individual').toLowerCase();
    const isBusiness = userType === 'business' || userType === 'business_contact';
    
    onClose();
    
    // Store the active tab in localStorage for business users (same pattern as Settings component's handleSectionChange)
    if (isBusiness) {
      localStorage.setItem('businessSettingsActiveTab', 'security');
    }
    
    // Navigate to settings page with hash (same pattern as Settings component's handleSectionChange)
    // The Settings component will detect the hash and set the active section accordingly
    const basePath = isBusiness ? '/settings/business' : '/settings/individual';
    navigate(`${basePath}#security`, { replace: true });
    
    // Ensure hash is set after navigation (fallback for React Router hash handling)
    setTimeout(() => {
      if (window.location.hash !== '#security') {
        window.location.hash = 'security';
      }
    }, 100);
  };

  const handleOverlayClick = (e) => {
    // Only close if clicking directly on the overlay, not on the modal content
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  const handleModalClick = (e) => {
    // Prevent clicks inside the modal from closing it
    e.stopPropagation();
  };

  return createPortal(
    <div 
      style={{
        position: 'fixed', 
        inset: 0, 
        backgroundColor: 'rgba(0,0,0,0.5)', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'center', 
        zIndex: 10002,
        backdropFilter: 'blur(4px)'
      }}
      onClick={handleOverlayClick}
    >
      <div 
        style={{ 
          backgroundColor: 'var(--card)', 
          borderRadius: 16, 
          padding: 32, 
          width: '100%', 
          maxWidth: 420, 
          boxShadow: 'var(--shadow-xl)',
          animation: 'slideIn 0.3s ease-out',
          position: 'relative',
          zIndex: 10003
        }}
        onClick={handleModalClick}
      >
        <div style={{ 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          marginBottom: 24 
        }}>
          <div style={{
            width: 64,
            height: 64,
            borderRadius: '50%',
            background: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            marginBottom: 16,
            boxShadow: '0 4px 12px rgba(245, 158, 11, 0.3)'
          }}>
            <span className="material-symbols-outlined" style={{ 
              fontSize: 32, 
              color: 'white' 
            }}>
              lock_open
            </span>
          </div>
          <h3 style={{ 
            margin: 0, 
            marginBottom: 8, 
            color: 'var(--text-primary)',
            fontSize: '24px',
            fontWeight: 700,
            textAlign: 'center'
          }}>
            {t('securityPinRequired', { ns: 'common' })}
          </h3>
          <p style={{ 
            margin: 0, 
            color: 'var(--text-muted)',
            fontSize: '14px',
            textAlign: 'center',
            lineHeight: '20px'
          }}>
            {t('setSecurityPinBeforeAction', { ns: 'common' })}
          </p>
        </div>

        {/* Buttons */}
        <div style={{ display: 'flex', gap: 12, flexDirection: 'column' }}>
          <button
            type="button"
            onClick={(e) => {
              e.preventDefault();
              e.stopPropagation();
              handleGoToSettings();
            }}
            style={{ 
              width: '100%',
              padding: '14px 20px', 
              borderRadius: 10, 
              border: 'none', 
              background: 'var(--accent)', 
              color: 'var(--text-inverse)', 
              cursor: 'pointer',
              fontSize: '15px',
              fontWeight: 600,
              transition: 'all 0.2s ease',
              boxShadow: 'var(--shadow-md)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
            onMouseEnter={(e) => {
              e.target.style.background = 'var(--accent-hover)';
              e.target.style.boxShadow = 'var(--shadow-lg)';
              e.target.style.transform = 'translateY(-1px)';
            }}
            onMouseLeave={(e) => {
              e.target.style.background = 'var(--accent)';
              e.target.style.boxShadow = 'var(--shadow-md)';
              e.target.style.transform = 'translateY(0)';
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
              settings
            </span>
            {t('goToSettings', { ns: 'common' })}
          </button>
          <button
            type="button"
            onClick={(e) => {
              e.preventDefault();
              e.stopPropagation();
              onClose();
            }}
            style={{ 
              width: '100%',
              padding: '14px 20px', 
              borderRadius: 10, 
              border: '2px solid var(--border-primary)', 
              background: 'var(--bg-input)', 
              color: 'var(--text-secondary)',
              cursor: 'pointer',
              fontSize: '15px',
              fontWeight: 600,
              transition: 'all 0.2s ease'
            }}
            onMouseEnter={(e) => {
              e.target.style.borderColor = 'var(--border-secondary)';
              e.target.style.background = 'var(--bg-hover)';
            }}
            onMouseLeave={(e) => {
              e.target.style.borderColor = 'var(--border-primary)';
              e.target.style.background = 'var(--bg-input)';
            }}
          >
            {t('cancel', { ns: 'common' })}
          </button>
        </div>
      </div>

      <style>{`
        @keyframes slideIn {
          from {
            opacity: 0;
            transform: translateY(-20px) scale(0.95);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }

        @media (max-width: 1024px) {
          div[style*="maxWidth: 420"] {
            max-width: min(90vw, 400px) !important;
          }
          div[style*="padding: 32"] {
            padding: 24px !important;
          }
        }

        @media (max-width: 768px) {
          div[style*="maxWidth: 420"] {
            max-width: min(95vw, 380px) !important;
          }
          div[style*="padding: 32"] {
            padding: 20px !important;
          }
          h3[style*="fontSize: '24px'"] {
            font-size: 20px !important;
          }
          div[style*="marginBottom: 24"] {
            margin-bottom: 18px !important;
          }
        }

        @media (max-width: 480px) {
          div[style*="maxWidth: 420"] {
            max-width: calc(100vw - 16px) !important;
          }
          div[style*="padding: 32"] {
            padding: 16px !important;
          }
          h3[style*="fontSize: '24px'"] {
            font-size: 18px !important;
          }
          p[style*="fontSize: '14px'"] {
            font-size: 12px !important;
          }
          div[style*="marginBottom: 24"] {
            margin-bottom: 16px !important;
          }
          button[style*="padding: '14px 20px'"] {
            padding: 10px 14px !important;
            font-size: 13px !important;
          }
          div[style*="width: 64"][style*="height: 64"] {
            width: 48px !important;
            height: 48px !important;
          }
          span[style*="fontSize: 32"][style*="color: 'white'"] {
            font-size: 24px !important;
          }
        }
      `}</style>
    </div>,
    document.body
  );
};

export default SetPinPromptModal;

